        {/* ── Voice Mode ── */}
        {mode === 'voice' && (
          <>
            <div ref={voiceChatRef} style={{ flex: 1, overflowY: 'auto', padding: 20, display: 'flex', flexDirection: 'column', gap: 12 }}>
