                {isConnecting ? <Loader2 size={24} className="spin" /> :
                 isListening ? <MicOff size={24} /> : <Mic size={24} />}
              </button>
              <div style={{ fontSize: 13, color: 'var(--nexus-text-muted)', maxWidth: 200 }}>
                {isConnecting ? 'Connecting...' :
                 isListening ? 'Listening — speak now' :
                 'Tap to start a voice call'}
              </div>
            </div>
          </>
        )}
      </div>

      <style>{`
        @keyframes fab-glow {
          0%, 100% { box-shadow: 0 4px 24px rgba(108, 99, 255, 0.35); }
          50% { box-shadow: 0 4px 32px rgba(108, 99, 255, 0.55), 0 0 60px rgba(108, 99, 255, 0.15); }
        }
        @keyframes fade-in-overlay {
          from { opacity: 0; } to { opacity: 1; }
        }
        @keyframes voice-pulse {
          0%, 100% { box-shadow: 0 0 0 0 rgba(108, 99, 255, 0.3); }
          50% { box-shadow: 0 0 0 12px rgba(108, 99, 255, 0); }
        }
        .ai-dot {
          animation: ai-bounce 1s infinite;
          font-weight: 800;
          font-size: 18px;
          line-height: 1;
        }
        @keyframes ai-bounce {
          0%, 100% { opacity: 0.3; transform: translateY(0); }
          50% { opacity: 1; transform: translateY(-3px); }
        }
      `}</style>
    </>
  );
}

'use client';

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, User, Sparkles } from 'lucide-react';

interface CopilotDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  role?: string;
}

interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
}

export default function CopilotDrawer({ isOpen, onClose, role = 'owner' }: CopilotDrawerProps) {

  const getGreeting = () => {
    if (role === 'vendor') return "Hello! I am your **Vendor Dispatch AI**. I can help you locate jobs and estimate payouts.";
    if (role === 'tenant') return "Hello! I am your **Tenant Support Agent**. I can help you understand your lease and request service.";
    return "Hello! I am your **Rentova AI Copilot**. How can I help you manage your portfolio today?";
  };

  const getTitle = () => {
    if (role === 'vendor') return "Vendor Dispatch AI";
    if (role === 'tenant') return "Tenant Support Agent";
    return "Rentova Copilot";
  };

  const [messages, setMessages] = useState<Message[]>([
    { id: '1', role: 'assistant', content: getGreeting() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', content: input.trim() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const res = await fetch('/api/ai/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: [...messages, userMsg] })
      });

      const data = await res.json();

      if (res.ok) {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: data.content }]);
      } else {
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: 'An error occurred while connecting to the AI.' }]);
      }
    } catch (err) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'assistant', content: 'Failed to contact Rentova Copilot.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <>
      <div 
        style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.3)', zIndex: 9998,
          opacity: isOpen ? 1 : 0, transition: 'opacity 0.3s ease'
        }}
        onClick={onClose}
      />
      <div 
        style={{
          position: 'fixed', top: 0, right: 0, width: '100%', maxWidth: 400,
          height: '100dvh',
          background: 'var(--nexus-bg)', zIndex: 9999,
          boxShadow: '-4px 0 24px rgba(0,0,0,0.1)',
          display: 'flex', flexDirection: 'column',
          transform: isOpen ? 'translateX(0)' : 'translateX(100%)',
          transition: 'transform 0.3s cubic-bezier(0.16, 1, 0.3, 1)'
        }}
      >
        {/* Header */}
        <div style={{ padding: '20px 24px', borderBottom: '1px solid var(--nexus-border)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: 'var(--nexus-bg)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'var(--nexus-accent)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff' }}>
              <Sparkles size={18} />
            </div>
            <div>
              <h2 style={{ fontWeight: 600, fontSize: 16 }}>{getTitle()}</h2>
              <span style={{ fontSize: 13, color: 'var(--nexus-text-secondary)' }}>Gemini 2.5 Flash</span>
            </div>
          </div>
          <button onClick={onClose} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nexus-text-secondary)' }}>
            <X size={20} />
          </button>
        </div>

        {/* Chat Feed */}
        <div style={{ flex: 1, overflowY: 'auto', padding: 24, display: 'flex', flexDirection: 'column', gap: 20 }}>
          {messages.map((msg) => (
            <div key={msg.id} style={{ display: 'flex', flexDirection: msg.role === 'user' ? 'row-reverse' : 'row', gap: 12, alignItems: 'flex-end' }}>
              <div style={{ 
                width: 28, height: 28, borderRadius: '50%', flexShrink: 0, display: 'flex', alignItems: 'center', justifyContent: 'center',
                background: msg.role === 'user' ? '#111' : 'rgba(0, 212, 170, 0.15)',
                color: msg.role === 'user' ? '#fff' : 'var(--nexus-accent)'
              }}>
                {msg.role === 'user' ? <User size={14} /> : <Bot size={16} />}
              </div>
              <div style={{
                maxWidth: '80%', padding: '12px 16px', borderRadius: 16, fontSize: 14, lineHeight: 1.5,
                background: msg.role === 'user' ? 'var(--nexus-accent)' : 'var(--nexus-bg-elevated)',
                color: msg.role === 'user' ? '#fff' : 'var(--nexus-text-primary)',
                borderBottomRightRadius: msg.role === 'user' ? 4 : 16,
                borderBottomLeftRadius: msg.role === 'assistant' ? 4 : 16,
              }}>
                {msg.content.split('**').map((text, i) => (i % 2 === 1 ? <strong key={i}>{text}</strong> : text))}
              </div>
            </div>
          ))}
          {isLoading && (
            <div style={{ display: 'flex', gap: 12, alignItems: 'flex-end' }}>
              <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'rgba(0, 212, 170, 0.15)', color: 'var(--nexus-accent)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Bot size={16} /></div>
              <div style={{ padding: '12px 16px', borderRadius: 16, background: 'var(--nexus-bg-elevated)', borderBottomLeftRadius: 4 }}>
                <div style={{ display: 'flex', gap: 4 }}>
                  <div className="dot-pulse" style={{ animationDelay: '0s' }}>•</div>
                  <div className="dot-pulse" style={{ animationDelay: '0.2s' }}>•</div>
                  <div className="dot-pulse" style={{ animationDelay: '0.4s' }}>•</div>
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div style={{ padding: '20px 20px calc(20px + env(safe-area-inset-bottom)) 20px', borderTop: '1px solid var(--nexus-border)', background: 'var(--nexus-bg)' }}>
          <form style={{ position: 'relative' }} onSubmit={sendMessage}>
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask Copilot anything..." 
              disabled={isLoading}
              style={{
                width: '100%', padding: '14px 44px 14px 16px', outline: 'none',
                background: 'var(--nexus-bg-elevated)', border: '1px solid var(--nexus-border)',
                borderRadius: 24, fontSize: 14, color: 'var(--nexus-text-primary)'
              }} 
            />
            <button 
              type="submit"
              disabled={!input.trim() || isLoading}
              style={{
                position: 'absolute', right: 6, top: 6, bottom: 6, width: 36,
                background: input.trim() && !isLoading ? 'var(--nexus-accent)' : 'transparent',
                color: input.trim() && !isLoading ? '#fff' : 'var(--nexus-text-secondary)',
                border: 'none', borderRadius: '50%', cursor: input.trim() && !isLoading ? 'pointer' : 'default',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                transition: 'all 0.2s'
              }}
            >
              <Send size={16} style={{ marginLeft: -2 }} />
            </button>
          </form>
          <div style={{ fontSize: 11, textAlign: 'center', color: 'var(--nexus-text-secondary)', marginTop: 12 }}>
            AI can make mistakes. Verify important financial data.
          </div>
        </div>
      </div>
      <style>{`
        @keyframes pulse { 0%, 100% { opacity: 0.4; } 50% { opacity: 1; } }
        .dot-pulse { animation: pulse 1s infinite; margin: 0 1px; color: var(--nexus-text-secondary); }
      `}</style>
    </>
  );
}

'use client';

import { useEffect, useState, useCallback, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import dynamic from 'next/dynamic';
import ActionQueue from '@/components/dashboard/ActionQueue';
import HierarchyNavigator from '@/components/spaces/HierarchyNavigator';
import { useRealtimeTable } from '@/lib/hooks/useRealtimeTable';
import type { DashboardKPIs, Space } from '@/types/database';

const PulseBar = dynamic(() => import('@/components/dashboard/PulseBar'), {
  ssr: false,
  loading: () => <div className="skeleton" style={{ height: 180, marginBottom: 32 }} />
});

const MoneyMap = dynamic(() => import('@/components/dashboard/MoneyMap'), {
  ssr: false,
  loading: () => <div className="skeleton" style={{ height: 400, marginBottom: 32 }} />
});

function DashboardContent() {
  const router = useRouter();
  const emptyKPIs: DashboardKPIs = {
    totalCashFlow: 0, cashFlowTrend: [], collectionRate: 0,
    totalPayments: 0, collectedPayments: 0, urgentRepairs: 0, criticalRepairs: 0
  };

  const [kpis, setKpis] = useState<DashboardKPIs>(emptyKPIs);
  const [spaces, setSpaces] = useState<Space[]>([]);
  const [treemapData, setTreemapData] = useState<any[]>([]);
  const [actions, setActions] = useState<any[]>([]);
  const [mounted, setMounted] = useState(false);
  const [dismissedActions, setDismissedActions] = useState<Set<string>>(new Set());

  const fetchDashboardData = useCallback(async () => {
    try {
      let isLiveSpaces = false;
      let isLiveKpis = false;
      let liveKpiData: DashboardKPIs | null = null;
      let liveSpacesData: Space[] = [];

      // Fetch KPIs
      const { getDashboardKPIs } = await import('@/lib/actions/payments');
      const kpiData = await getDashboardKPIs();
      if (kpiData?.data) {
        liveKpiData = kpiData.data;
        if (kpiData.data.totalPayments > 0 || kpiData.data.urgentRepairs > 0) {
          isLiveKpis = true;
        }
      }

      // Fetch spaces
      const { getSpaces } = await import('@/lib/actions/spaces');
      const spacesData = await getSpaces();
      if (spacesData && !spacesData.error && spacesData.data) {
        liveSpacesData = spacesData.data;
        isLiveSpaces = true;
      }

      // Core logic: ALWAYS sync the exact database state (even if empty zeros).
      if (liveKpiData) setKpis(liveKpiData);

      setSpaces(liveSpacesData);
      const rentable = liveSpacesData.filter((s: Space) => s.base_rent && Number(s.base_rent) > 0);
      if (rentable.length > 0) {
        setTreemapData(
          rentable.map((s: Space) => ({
            id: s.id,
            name: s.name,
            type: s.type,
            rent: Number(s.base_rent) || 0,
            status: s.status === 'occupied' ? ('paid' as const) : s.status === 'vacant' ? ('vacant' as const) : ('pending' as const),
          }))
        );
      } else {
        setTreemapData([]);
      }

      // Fetch action queue items
      const { getActionQueueItems } = await import('@/lib/actions/maintenance');
      const actionsData = await getActionQueueItems();
      if (actionsData) {
        const formattedActions = [
          ...(actionsData.tickets.map(t => ({
            id: t.id,
            type: 'maintenance' as const,
            title: t.title,
            subtitle: `Space: ${(t.space as Record<string,unknown>)?.name || 'Unknown'}`,
            timestamp: 'Just now',
            severity: t.ai_severity === 'critical' ? 'critical' : t.ai_severity === 'high' ? 'high' : 'medium',
            cta: 'View',
            amount: 0,
          }))),
          ...(actionsData.payments.map(p => ({
            id: String(p.id),
            type: 'payment' as const,
            title: `Late Rent: $${Number(p.amount)}`,
            subtitle: `Tenant: ${(p.tenant as Record<string,unknown>)?.full_name || 'Unknown'} | Due: ${p.due_date}`,
            timestamp: p.due_date as string,
            severity: undefined,
            cta: 'Review',
            amount: Number(p.amount),
          })))
        ];
        if (formattedActions.length > 0) setActions(formattedActions);
      }
    } catch {
      // API error handler
    }
  }, []);

  useEffect(() => {
    setMounted(true);
    fetchDashboardData();
  }, [fetchDashboardData]);

  // Real-time subscriptions — refresh dashboard on data changes
  useRealtimeTable('rent_payments', fetchDashboardData);
  useRealtimeTable('maintenance_tickets', fetchDashboardData);
  useRealtimeTable('spaces', fetchDashboardData);

  // Route action queue button clicks to the appropriate page
  const handleActionApprove = (id: string, type: string) => {
    switch (type) {
      case 'maintenance':
        router.push('/maintenance');
        break;
      case 'payment':
        router.push('/payments');
        break;
      case 'lease':
        router.push('/leases');
        break;
      default:
        router.push('/notifications');
    }
  };

  // Snooze = dismiss the action item from the queue
  const handleActionSnooze = (id: string) => {
    setDismissedActions(prev => new Set(prev).add(id));
  };

  // Filter out dismissed actions
  const visibleActions = actions.filter(a => !dismissedActions.has(a.id));

  if (!mounted) return null;

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Dashboard</h1>
          <p className="page-subtitle">
            Your property portfolio at a glance
          </p>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn-secondary" style={{ fontSize: 13 }} onClick={() => window.print()}>
            Export Report
          </button>
          <button className="btn-primary" style={{ fontSize: 13 }} onClick={() => router.push('/spaces')}>
            + Add Property
          </button>
        </div>
      </div>

      {/* Row 1: Pulse Bar */}
      <PulseBar kpis={kpis} />

      {/* Row 2: Money Map */}
      <MoneyMap spaces={treemapData} />

      {/* Row 3: Action Queue */}
      <ActionQueue
        items={visibleActions}
        onApprove={handleActionApprove}
        onSnooze={handleActionSnooze}
      />

      {/* Row 4: Hierarchy Navigator */}
      <HierarchyNavigator
        spaces={spaces}
        onSelect={(space) => router.push(`/spaces`)}
        onReparent={(spaceId, newParentId) => router.push('/spaces')}
        onAdd={() => router.push('/spaces')}
      />
    </div>
  );
}

export default function DashboardPage() {
  return (
    <Suspense fallback={<div style={{ padding: 48, color: 'var(--nexus-text-secondary)', textAlign: 'center' }}>Loading Dashboard Engine...</div>}>
      <DashboardContent />
    </Suspense>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';
import {
  CreditCard, Wrench, FileText, Shield, CheckCircle,
  AlertTriangle, Clock, ChevronRight, Calendar, DollarSign,
} from 'lucide-react';
import { useRouter } from 'next/navigation';
import { formatDistanceToNow, format, isPast, parseISO } from 'date-fns';
import ActionQueue from '@/components/dashboard/ActionQueue';
import { useRealtimeTable } from '@/lib/hooks/useRealtimeTable';
import type { TenantKPIs, TenantActionItem } from '@/lib/actions/tenant-dashboard';

export default function TenantDashboard() {
