  const [mounted, setMounted] = useState(false);
  const [loading, setLoading] = useState(true);
  const [kpis, setKpis] = useState<TenantKPIs>({
    nextPayment: null,
    activeRequests: 0,
    lease: null,
    trustScore: null,
  });
