'use server';

import { createClient } from '@/lib/supabase/server';
import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import { headers } from 'next/headers';

export async function signUp(formData: {
  email: string;
  password: string;
  full_name: string;
  role: 'owner' | 'tenant' | 'manager' | 'vendor';
}) {
  const supabase = await createClient();

  const { data, error } = await supabase.auth.signUp({
    email: formData.email,
    password: formData.password,
    options: {
      data: {
        full_name: formData.full_name,
        role: formData.role,
      },
    },
  });

  if (error) return { error: error.message };
  return { data: { user: data.user } };
}

export async function signIn(formData: { email: string; password: string }) {
  const supabase = await createClient();

  const { data, error } = await supabase.auth.signInWithPassword({
    email: formData.email,
    password: formData.password,
  });

  if (error) return { error: error.message };
  revalidatePath('/', 'layout');
  return { data: { user: data.user } };
}

export async function signOut() {
  const supabase = await createClient();
  await supabase.auth.signOut();
  revalidatePath('/', 'layout');
  redirect('/auth/login');
}

export async function signInWithGoogle() {
  const supabase = await createClient();
  const isProduction = process.env.NODE_ENV === 'production';

  // Violently override ANY broken Vercel environment variables in production
  const origin = isProduction 
    ? 'https://nexus-property-hub.vercel.app' 
    : (process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000');

  const { data, error } = await supabase.auth.signInWithOAuth({
    provider: 'google',
    options: {
      redirectTo: `${origin}/auth/callback`,
    },
  });

  if (error) return { error: error.message };
  return { data: { url: data.url } };
}

export async function getCurrentUser() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const { data: profile } = await supabase
    .from('users')
    .select('*')
    .eq('id', user.id)
    .single();

  return profile;
}

export async function deleteAccount() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return { error: 'Not authenticated' };

  // Scrub profile data (cascade dependencies handle the rest based on foreign keys)
  const { error } = await supabase
    .from('users')
    .delete()
    .eq('id', user.id);

  if (error) return { error: error.message };

  // Destroy auth session
  await supabase.auth.signOut();

  return { success: true };
}

'use server';

import { createClient } from '@/lib/supabase/server';
import { getCurrentUser } from '@/lib/actions/auth';

export interface TenantKPIs {
  nextPayment: {
    amount: number;
    dueDate: string;
    spaceName: string;
    status: string;
    paymentId: string | null;
  } | null;
  activeRequests: number;
  lease: {
    id: string;
    status: string;
    spaceName: string;
    monthlyRent: number;
    endDate: string | null;
    autoRenew: boolean;
  } | null;
  trustScore: number | null;
}

export interface TenantActionItem {
  id: string;
  type: 'payment' | 'maintenance' | 'lease';
  title: string;
  subtitle: string;
  timestamp: string;
  severity?: string;
  cta: string;
  amount?: number;
}

export async function getTenantDashboardData(): Promise<{
  kpis: TenantKPIs;
  actions: TenantActionItem[];
  recentPayments: Array<{ amount: number; dueDate: string; status: string; spaceName: string }>;
}> {
  const supabase = await createClient();
  const profile = await getCurrentUser();

  const empty: TenantKPIs = {
    nextPayment: null,
    activeRequests: 0,
    lease: null,
    trustScore: null,
  };

  if (!profile || profile.role !== 'tenant') {
    return { kpis: empty, actions: [], recentPayments: [] };
  }

  const tenantId = profile.id;

  // Run all queries in parallel
  const [paymentsResult, ticketsResult, leaseResult, trustResult, recentPaymentsResult] = await Promise.all([
    // Next upcoming or overdue payment
    supabase
      .from('rent_payments')
      .select('id, amount, due_date, status, lease:leases(space:spaces(name))')
      .eq('tenant_id', tenantId)
      .in('status', ['pending', 'failed', 'processing'])
      .order('due_date', { ascending: true })
      .limit(1),

    // Active maintenance tickets
    supabase
      .from('maintenance_tickets')
      .select('id, title, status, ai_severity, created_at, space:spaces(name)')
      .eq('reporter_id', tenantId)
      .in('status', ['open', 'triaged', 'in_progress', 'vendor_assigned'])
      .order('priority', { ascending: true }),

    // Active lease
    supabase
      .from('leases')
      .select('id, status, monthly_rent, end_date, auto_renew, split_pct, space:spaces(name)')
      .eq('tenant_id', tenantId)
      .in('status', ['active', 'pending'])
      .order('created_at', { ascending: false })
      .limit(1),

    // Trust score
    supabase
      .from('trust_scores')
      .select('score')
      .eq('user_id', tenantId)
      .single(),

    // Recent payment history (last 6)
    supabase
      .from('rent_payments')
      .select('amount, due_date, status, lease:leases(space:spaces(name))')
      .eq('tenant_id', tenantId)
      .order('due_date', { ascending: false })
      .limit(6),
  ]);

  // Build KPIs
  const nextPaymentRow = paymentsResult.data?.[0] as any;
  const leaseRow = leaseResult.data?.[0] as any;

  const kpis: TenantKPIs = {
    nextPayment: nextPaymentRow ? {
      amount: Number(nextPaymentRow.amount),
      dueDate: nextPaymentRow.due_date,
      spaceName: nextPaymentRow.lease?.space?.name || 'Unknown',
      status: nextPaymentRow.status,
      paymentId: nextPaymentRow.id,
    } : null,
    activeRequests: ticketsResult.data?.length ?? 0,
    lease: leaseRow ? {
      id: leaseRow.id,
      status: leaseRow.status,
      spaceName: leaseRow.space?.name || 'Unknown',
      monthlyRent: Number(leaseRow.monthly_rent) * Number(leaseRow.split_pct || 100) / 100,
      endDate: leaseRow.end_date,
      autoRenew: leaseRow.auto_renew,
    } : null,
    trustScore: trustResult.data?.score ?? null,
  };

  // Build action items
  const actions: TenantActionItem[] = [];

  // Overdue / failed payments become action items
  if (nextPaymentRow && (nextPaymentRow.status === 'failed' || isOverdue(nextPaymentRow.due_date))) {
    actions.push({
      id: nextPaymentRow.id,
      type: 'payment',
      title: nextPaymentRow.status === 'failed'
        ? `Payment Failed — $${Number(nextPaymentRow.amount)}`
        : `Rent Overdue — $${Number(nextPaymentRow.amount)}`,
      subtitle: nextPaymentRow.lease?.space?.name || 'Unknown space',
      timestamp: nextPaymentRow.due_date,
      severity: 'critical',
      cta: 'Pay Now',
      amount: Number(nextPaymentRow.amount),
    });
  }

  // Open maintenance tickets become action items
  if (ticketsResult.data) {
    for (const ticket of ticketsResult.data) {
      const t = ticket as any;
      actions.push({
        id: t.id,
        type: 'maintenance',
        title: t.title,
        subtitle: `${t.space?.name || 'Unknown space'} · ${t.status.replace('_', ' ')}`,
        timestamp: t.created_at,
        severity: t.ai_severity === 'critical' ? 'critical' : t.ai_severity === 'high' ? 'high' : undefined,
        cta: 'View',
      });
    }
  }

  // Pending leases needing action
  if (leaseRow && leaseRow.status === 'pending') {
    actions.push({
      id: leaseRow.id,
      type: 'lease',
      title: 'Lease Pending Signature',
      subtitle: leaseRow.space?.name || 'Unknown space',
      timestamp: new Date().toISOString(),
      cta: 'Review',
    });
  }

  // Recent payments history
  const recentPayments = (recentPaymentsResult.data ?? []).map((p: any) => ({
    amount: Number(p.amount),
    dueDate: p.due_date,
    status: p.status,
    spaceName: p.lease?.space?.name || 'Unknown',
  }));

  return { kpis, actions, recentPayments };
}

function isOverdue(dueDate: string): boolean {
  return new Date(dueDate) < new Date(new Date().toISOString().split('T')[0]);
}

'use server';

import { createClient } from '@/lib/supabase/server';
import { getCurrentUser } from '@/lib/actions/auth';

export interface VendorKPIs {
  assignedTickets: number;
  inProgress: number;
  completedThisMonth: number;
  avgResolutionHours: number | null;
}

export interface VendorTicket {
  id: string;
  title: string;
  description: string | null;
  spaceName: string;
  severity: string | null;
  category: string | null;
  priority: number;
  status: string;
  costEstimate: number | null;
  createdAt: string;
  reporterName: string;
}

export async function getVendorDashboardData(): Promise<{
  kpis: VendorKPIs;
  assignedTickets: VendorTicket[];
  recentlyCompleted: VendorTicket[];
}> {
  const supabase = await createClient();
  const profile = await getCurrentUser();

  const empty: VendorKPIs = {
    assignedTickets: 0,
    inProgress: 0,
    completedThisMonth: 0,
    avgResolutionHours: null,
  };

  if (!profile || profile.role !== 'vendor') {
    return { kpis: empty, assignedTickets: [], recentlyCompleted: [] };
  }

  const vendorId = profile.id;
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();

  // Run all queries in parallel
  const [activeResult, completedResult] = await Promise.all([
    // Active tickets assigned to this vendor
    supabase
      .from('maintenance_tickets')
      .select(`
        id, title, description, priority, status, ai_severity, ai_category,
        ai_cost_estimate, created_at,
        space:spaces(name),
        reporter:users!maintenance_tickets_reporter_id_fkey(full_name)
      `)
      .eq('assigned_to', vendorId)
      .in('status', ['vendor_assigned', 'in_progress', 'triaged'])
      .order('priority', { ascending: true })
      .order('created_at', { ascending: false }),

    // Completed tickets this month
    supabase
      .from('maintenance_tickets')
      .select(`
        id, title, description, priority, status, ai_severity, ai_category,
        ai_cost_estimate, created_at, resolved_at,
        space:spaces(name),
        reporter:users!maintenance_tickets_reporter_id_fkey(full_name)
      `)
      .eq('assigned_to', vendorId)
      .in('status', ['resolved', 'closed'])
      .gte('resolved_at', monthStart)
      .order('resolved_at', { ascending: false })
      .limit(20),
  ]);

  const activeTickets = (activeResult.data ?? []) as any[];
  const completedTickets = (completedResult.data ?? []) as any[];

  // Calculate average resolution time for completed tickets
  let avgResolutionHours: number | null = null;
  if (completedTickets.length > 0) {
    const totalHours = completedTickets.reduce((sum: number, t: any) => {
      if (t.resolved_at && t.created_at) {
        const created = new Date(t.created_at).getTime();
        const resolved = new Date(t.resolved_at).getTime();
        return sum + (resolved - created) / (1000 * 60 * 60);
      }
      return sum;
    }, 0);
    avgResolutionHours = Math.round((totalHours / completedTickets.length) * 10) / 10;
  }

  const mapTicket = (t: any): VendorTicket => ({
    id: t.id,
    title: t.title,
    description: t.description,
    spaceName: t.space?.name || 'Unknown',
    severity: t.ai_severity,
    category: t.ai_category,
    priority: t.priority,
    status: t.status,
    costEstimate: t.ai_cost_estimate ? Number(t.ai_cost_estimate) : null,
    createdAt: t.created_at,
    reporterName: t.reporter?.full_name || 'Unknown',
  });

  const kpis: VendorKPIs = {
    assignedTickets: activeTickets.length,
    inProgress: activeTickets.filter(t => t.status === 'in_progress').length,
    completedThisMonth: completedTickets.length,
    avgResolutionHours,
  };

  return {
    kpis,
    assignedTickets: activeTickets.map(mapTicket),
    recentlyCompleted: completedTickets.slice(0, 5).map(mapTicket),
  };
}

import { createServiceClient } from '@/lib/supabase/server';

type NotificationType = 'payment_reminder' | 'maintenance_update' | 'lease_action' | 'trust_update' | 'system';
type NotificationChannel = 'app' | 'sms' | 'email';

interface DispatchOptions {
  userId: string;
  type: NotificationType;
  title: string;
  body: string;
  channels?: NotificationChannel[];
  meta?: Record<string, any>;
}

/**
 * Universal Notification Dispatcher
 * Instantly broadcasts mult-channel alerts (In-App, SMS, Email).
 * Includes automatic Mock Fallback for local development.
 */
export async function dispatchNotification({
  userId,
  type,
  title,
  body,
  channels = ['app'],
  meta = {}
}: DispatchOptions) {
  const supabase = await createServiceClient();

  try {
    // 1. ALWAYS dispatch to the In-App Notification Center
    if (channels.includes('app')) {
      await supabase.from('notifications').insert({
        user_id: userId,
        type,
        title,
        body,
        channels,
        meta
      });
    }

    // Attempt external channels?
    if (channels.includes('sms') || channels.includes('email')) {
      // Need user's contact info
      const { data: user } = await supabase
        .from('users')
        .select('phone, email, full_name')
        .eq('id', userId)
        .single();

      if (!user) {
        console.error(`❌ DispatchFailed: User ${userId} not found.`);
        return;
      }

      // 2. Dispatch SMS via TWILIO
      if (channels.includes('sms')) {
        const twilioSid = process.env.TWILIO_ACCOUNT_SID;
        const twilioAuth = process.env.TWILIO_AUTH_TOKEN;
        const twilioPhone = process.env.TWILIO_PHONE_NUMBER;

        if (!twilioSid || twilioSid === 'your-twilio-sid' || !user.phone) {
          console.log(`\x1b[36m[MOCK SMS]\x1b[0m 📱 To: ${user.full_name} (${user.phone || 'No Phone Number'})\n   Body: "${title} - ${body}"`);
        } else {
          // Real Twilio API Call
          const params = new URLSearchParams();
          params.append('To', user.phone);
          params.append('From', twilioPhone!);
          params.append('Body', `${title}\n\n${body}`);

          const encodedAuth = Buffer.from(`${twilioSid}:${twilioAuth}`).toString('base64');

          await fetch(`https://api.twilio.com/2010-04-01/Accounts/${twilioSid}/Messages.json`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
              'Authorization': `Basic ${encodedAuth}`
            },
            body: params.toString()
          }).catch(err => console.error('Twilio Error:', err));
        }
      }

      // 3. Dispatch Email via RESEND
      if (channels.includes('email') && user.email) {
        const resendKey = process.env.RESEND_API_KEY;

        if (!resendKey || resendKey === 'your-resend-api-key') {
          console.log(`\x1b[35m[MOCK EMAIL]\x1b[0m 📧 To: ${user.email} (Subject: ${title})\n   Body: "${body}"`);
        } else {
          // Real Resend API Call
          await fetch('https://api.resend.com/emails', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${resendKey}`
            },
            body: JSON.stringify({
              from: 'Rentova Hub <nexus@yourdomain.com>',
              to: [user.email],
              subject: title,
              html: `<div style="font-family:sans-serif; padding: 20px;"><h2>${title}</h2><p>${body}</p><br/><hr/><small>Rentova Automated System</small></div>`
            })
          }).catch(err => console.error('Resend Error:', err));
        }
      }
    }

  } catch (error) {
    console.error('CRITICAL: Notification Dispatcher Failed', error);
  }
}

import { NextRequest, NextResponse } from 'next/server';

// ─── Rate Limiter ─────────────────────────────────
// Uses Upstash Redis in production for cross-isolate consistency.
// Falls back to in-memory store when UPSTASH_REDIS_REST_URL is not set.

const RATE_LIMITS = {
  read: { windowMs: 60000, maxRequests: 100 },
  write: { windowMs: 60000, maxRequests: 20 },
};

function getClientIdentifier(request: NextRequest): string {
  return request.headers.get('x-forwarded-for') ||
    request.headers.get('x-real-ip') ||
    'anonymous';
}

function isWriteMethod(method: string): boolean {
  return ['POST', 'PUT', 'PATCH', 'DELETE'].includes(method.toUpperCase());
}

// ─── Upstash Redis Rate Limiter ───────────────────
let upstashLimiter: { read: any; write: any } | null = null;

async function getUpstashLimiter() {
  if (upstashLimiter) return upstashLimiter;

  const url = process.env.UPSTASH_REDIS_REST_URL;
  const token = process.env.UPSTASH_REDIS_REST_TOKEN;

  if (!url || !token) return null;

  const { Ratelimit } = await import('@upstash/ratelimit');
  const { Redis } = await import('@upstash/redis');

  const redis = new Redis({ url, token });

  upstashLimiter = {
    read: new Ratelimit({
      redis,
      limiter: Ratelimit.slidingWindow(100, '60 s'),
      prefix: 'nexus:rl:read',
    }),
    write: new Ratelimit({
      redis,
      limiter: Ratelimit.slidingWindow(20, '60 s'),
      prefix: 'nexus:rl:write',
    }),
  };

  return upstashLimiter;
}

// ─── In-Memory Fallback ───────────────────────────
const memoryStore = new Map<string, { count: number; timestamp: number }>();

function checkMemoryRateLimit(ip: string, isWrite: boolean): { allowed: boolean; retryAfter?: number } {
  const limits = isWrite ? RATE_LIMITS.write : RATE_LIMITS.read;
  const key = `${ip}:${isWrite ? 'write' : 'read'}`;
  const now = Date.now();
  const record = memoryStore.get(key);

  if (!record || now - record.timestamp > limits.windowMs) {
    memoryStore.set(key, { count: 1, timestamp: now });
    return { allowed: true };
  }

  if (record.count >= limits.maxRequests) {
    const retryAfter = Math.ceil((record.timestamp + limits.windowMs - now) / 1000);
    return { allowed: false, retryAfter };
  }

  record.count++;
  return { allowed: true };
}

// Cleanup stale in-memory entries every 5 minutes
if (typeof setInterval !== 'undefined') {
  setInterval(() => {
    const now = Date.now();
    for (const [key, value] of memoryStore.entries()) {
      if (now - value.timestamp > 300000) memoryStore.delete(key);
    }
  }, 300000);
}

// ─── Exported Check ───────────────────────────────
export async function checkRateLimit(request: NextRequest): Promise<NextResponse | null> {
  const ip = getClientIdentifier(request);
  const isWrite = isWriteMethod(request.method);

  // Try Upstash first
  const limiter = await getUpstashLimiter();
  if (limiter) {
    const rl = isWrite ? limiter.write : limiter.read;
    const { success, limit, remaining, reset } = await rl.limit(ip);

    if (!success) {
      const retryAfter = Math.ceil((reset - Date.now()) / 1000);
      return NextResponse.json(
        { error: 'Rate limit exceeded', retryAfter },
        {
          status: 429,
          headers: {
            'Retry-After': String(retryAfter),
            'X-RateLimit-Limit': String(limit),
            'X-RateLimit-Remaining': '0',
            'X-RateLimit-Reset': String(reset),
          },
        }
      );
    }
    return null;
  }

  // Fallback to in-memory
  const result = checkMemoryRateLimit(ip, isWrite);
  if (!result.allowed) {
    return NextResponse.json(
      { error: 'Rate limit exceeded', retryAfter: result.retryAfter },
      {
        status: 429,
        headers: {
          'Retry-After': String(result.retryAfter || 60),
          'X-RateLimit-Limit': String(isWrite ? RATE_LIMITS.write.maxRequests : RATE_LIMITS.read.maxRequests),
          'X-RateLimit-Remaining': '0',
        },
      }
    );
  }

  return null;
}

import { updateSession } from '@/lib/supabase/middleware';
import { checkRateLimit } from '@/lib/rate-limit';
import { NextRequest, NextResponse } from 'next/server';

export async function middleware(request: NextRequest) {
  const isApi = request.nextUrl.pathname.startsWith('/api');

  // Apply rate limiting to API routes
  if (isApi) {
    const ip = request.headers.get('x-forwarded-for') ?? request.headers.get('x-real-ip') ?? '127.0.0.1';
    const isLocal = ip === '127.0.0.1' || ip === '::1';

    if (!isLocal) {
      const rateLimitResponse = await checkRateLimit(request);
      if (rateLimitResponse) return rateLimitResponse;
    }
  }

  return await updateSession(request);
}

